#!/usr/bin/env bash

# NOTE: Generated by ChatGPT5.4 on 17 March 2026

set -euo pipefail

if [[ $# -lt 1 ]]; then
    echo "Usage: $0 <checkpoints_dir>"
    exit 1
fi

BASE_DIR="$1"

if [[ ! -d "$BASE_DIR" ]]; then
    echo "Error: Directory '$BASE_DIR' does not exist."
    exit 1
fi

for ckpt in "${BASE_DIR}"/checkpoint-*; do
    [[ -d "$ckpt" ]] || continue

    ckpt_name=$(basename "$ckpt")
    outfile="${BASE_DIR}/${ckpt_name}_eval_log.txt"

    echo "=== Evaluating $ckpt ==="
    echo "Output -> $outfile"

    cmd=(
        python run.py evaluate
        --model_id "$ckpt"
        --n_tests 1319
        --output_file "$outfile"
    )

    printf 'Command:'
    printf ' %q' "${cmd[@]}"
    printf '\n'

    "${cmd[@]}"
done